import{_ as t}from"./chunks/pricing.xnwHCEuz.js";import{_ as e,o as s,c as n,a2 as r}from"./chunks/framework.BflysNKA.js";const d="/images/tutorial/usage-logs.png",g=JSON.parse('{"title":"快速接入","description":"","frontmatter":{},"headers":[],"relativePath":"guide/quick-start.md","filePath":"guide/quick-start.md","lastUpdated":1780486473000}'),p={name:"guide/quick-start.md"};function l(i,a,o,c,h,u){return s(),n("div",null,[...a[0]||(a[0]=[r('<h1 id="快速接入" tabindex="-1">快速接入 <a class="header-anchor" href="#快速接入" aria-label="Permalink to &quot;快速接入&quot;">​</a></h1><p>按顺序完成以下步骤，首次接入通常 10 分钟内跑通。<strong>顺序很重要，跳过任何一步都会调用失败。</strong></p><h2 id="你需要准备什么" tabindex="-1">你需要准备什么 <a class="header-anchor" href="#你需要准备什么" aria-label="Permalink to &quot;你需要准备什么&quot;">​</a></h2><table tabindex="0"><thead><tr><th>步骤</th><th>操作</th><th>预计耗时</th></tr></thead><tbody><tr><td>1</td><td><a href="/guide/registration">注册并登录</a></td><td>1 分钟</td></tr><tr><td>2</td><td><a href="/guide/recharge">充值 ¥10</a></td><td>2 分钟</td></tr><tr><td>3</td><td><a href="/guide/create-key">创建 Key</a></td><td>1 分钟</td></tr><tr><td>4</td><td>复制模型名</td><td>30 秒</td></tr><tr><td>5</td><td>配置工具</td><td>5 分钟</td></tr><tr><td>6</td><td>发送测试消息并核对日志</td><td>30 秒</td></tr></tbody></table><h2 id="详细步骤" tabindex="-1">详细步骤 <a class="header-anchor" href="#详细步骤" aria-label="Permalink to &quot;详细步骤&quot;">​</a></h2><h3 id="_1-注册并登录" tabindex="-1">1. 注册并登录 <a class="header-anchor" href="#_1-注册并登录" aria-label="Permalink to &quot;1. 注册并登录&quot;">​</a></h3><p>打开 <a href="https://xiaolan1.cn" target="_blank" rel="noreferrer">小蓝中转站 官网</a>，用用户名 + 密码注册，再登录。详见 <a href="/guide/registration">注册与登录</a>。</p><h3 id="_2-充值" tabindex="-1">2. 充值 <a class="header-anchor" href="#_2-充值" aria-label="Permalink to &quot;2. 充值&quot;">​</a></h3><p>登录后点侧边栏 <strong>钱包</strong>，选 ¥10，用支付宝或微信完成支付，余额即时到账。详见 <a href="/guide/recharge">充值</a>。</p><h3 id="_3-创建-key" tabindex="-1">3. 创建 Key <a class="header-anchor" href="#_3-创建-key" aria-label="Permalink to &quot;3. 创建 Key&quot;">​</a></h3><p>点侧边栏 <strong>API 密钥</strong> → <strong>创建 API 密钥</strong>，名称填 <code>设备-工具</code>（如 <code>Mac-Claude</code>），分组选 <code>auto</code>，额度先开「无限配额」。</p><p><strong>保存后立即复制完整 Key</strong>——它只完整显示这一次。详见 <a href="/guide/create-key">创建专属 Key</a>。</p><h3 id="_4-复制模型名" tabindex="-1">4. 复制模型名 <a class="header-anchor" href="#_4-复制模型名" aria-label="Permalink to &quot;4. 复制模型名&quot;">​</a></h3><p>点顶部导航 <strong>模型广场</strong>，搜索你要用的模型，<strong>点模型名即可复制</strong>：</p><p><img src="'+t+'" alt="模型广场：① 搜索模型，② 点模型名即可复制，配置工具的 model 字段以此为准"></p><p>不要自己编模型名，一律以模型广场显示的为准。</p><h3 id="_5-配置工具" tabindex="-1">5. 配置工具 <a class="header-anchor" href="#_5-配置工具" aria-label="Permalink to &quot;5. 配置工具&quot;">​</a></h3><p>选一个工具，把 <strong>Key、地址、模型名</strong> 填进去：</p><table tabindex="0"><thead><tr><th>想做什么</th><th>用什么</th><th>配置指南</th></tr></thead><tbody><tr><td>先确认接口能用</td><td>Cherry Studio</td><td><a href="/apps/cherry-studio">配置指南</a></td></tr><tr><td>终端里改代码</td><td>Claude Code</td><td><a href="/deploy/claude-code">配置指南</a></td></tr><tr><td>OpenAI 风格 CLI</td><td>Codex</td><td><a href="/deploy/codex">配置指南</a></td></tr><tr><td>长上下文/大仓库</td><td>Gemini CLI</td><td><a href="/deploy/gemini-cli">配置指南</a></td></tr></tbody></table><h3 id="_6-发送测试消息并核对日志" tabindex="-1">6. 发送测试消息并核对日志 <a class="header-anchor" href="#_6-发送测试消息并核对日志" aria-label="Permalink to &quot;6. 发送测试消息并核对日志&quot;">​</a></h3><p>在工具里发送一句「你好」。能收到回复，说明链路已通。</p><p>回到控制台 <strong>使用日志</strong>，能看到刚才这次调用的模型、耗时和消耗，就算真正接入成功了：</p><p><img src="'+d+`" alt="使用日志：每次调用都会记录时间 / 模型 / 耗时 / 消耗"></p><div class="tip custom-block"><p class="custom-block-title">新账号的日志</p><p>刚注册时，使用日志里通常只有一条「新用户注册赠送」记录。等你用工具发过请求后，才会出现带模型名的调用明细。</p></div><h2 id="常用参数速查" tabindex="-1">常用参数速查 <a class="header-anchor" href="#常用参数速查" aria-label="Permalink to &quot;常用参数速查&quot;">​</a></h2><p>不同工具的地址格式不同，这是最容易出错的地方：</p><div class="language-txt vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span># OpenAI 兼容工具（Codex、脚本等）—— 要加 /v1</span></span>
<span class="line"><span>Base URL: https://xiaolan1.cn/v1</span></span>
<span class="line"><span>API Key: sk-你的专属Key</span></span>
<span class="line"><span>Model: 从模型广场复制</span></span>
<span class="line"><span></span></span>
<span class="line"><span># Claude Code —— 不要加 /v1</span></span>
<span class="line"><span>ANTHROPIC_BASE_URL: https://xiaolan1.cn</span></span>
<span class="line"><span></span></span>
<span class="line"><span># Gemini CLI —— 不要加 /v1</span></span>
<span class="line"><span>GOOGLE_GEMINI_BASE_URL: https://xiaolan1.cn</span></span>
<span class="line"><span></span></span>
<span class="line"><span># Cherry Studio —— 不要加 /v1</span></span>
<span class="line"><span>API 地址: https://xiaolan1.cn</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br></div></div><div class="warning custom-block"><p class="custom-block-title">最常见的错误</p><p>Claude Code、Gemini CLI 和 Cherry Studio 的地址<strong>不要加 <code>/v1</code></strong>；而 Codex 和 OpenAI 兼容工具<strong>必须加 <code>/v1</code></strong>。填反了会报 404。</p></div><div class="tip custom-block"><p class="custom-block-title">新手建议</p><p>分组先选 <code>auto</code>，模型先选轻量的。跑通后再切换到代码模型。</p></div><h2 id="环境安装" tabindex="-1">环境安装 <a class="header-anchor" href="#环境安装" aria-label="Permalink to &quot;环境安装&quot;">​</a></h2><p>需要 CLI 工具的话，先装开发环境：</p><ul><li><a href="/beginner/windows-env">Windows 环境准备</a></li><li><a href="/beginner/macos-env">macOS 环境准备</a></li></ul><p>遇到问题看 <a href="/support/troubleshooting">排障手册</a>。</p>`,33)])])}const _=e(p,[["render",l]]);export{g as __pageData,_ as default};
